<?php
if ( ! defined( 'ABSPATH' ) ) { exit; }
final class EBM_Admin {
	public static function init(){add_action('admin_menu',array(__CLASS__,'menu'));add_action('admin_post_ebm_save_settings',array(__CLASS__,'save_settings'));add_action('admin_post_ebm_save_job',array(__CLASS__,'save_job'));add_action('admin_post_ebm_save_addon',array(__CLASS__,'save_addon'));add_action('admin_post_ebm_update_booking',array(__CLASS__,'update_booking'));}
	public static function menu(){add_menu_page(__('Electrical Bookings','electrical-booking-manager'),__('Electrical Bookings','electrical-booking-manager'),'manage_options','ebm-bookings',array(__CLASS__,'bookings'),'dashicons-calendar-alt',26);add_submenu_page('ebm-bookings',__('Bookings','electrical-booking-manager'),__('Bookings','electrical-booking-manager'),'manage_options','ebm-bookings',array(__CLASS__,'bookings'));add_submenu_page('ebm-bookings',__('Jobs & Add-ons','electrical-booking-manager'),__('Jobs & Add-ons','electrical-booking-manager'),'manage_options','ebm-jobs',array(__CLASS__,'jobs'));add_submenu_page('ebm-bookings',__('Settings','electrical-booking-manager'),__('Settings','electrical-booking-manager'),'manage_options','ebm-settings',array(__CLASS__,'settings'));}
	private static function cap(){if(!current_user_can('manage_options')){wp_die(esc_html__('Permission denied.','electrical-booking-manager'));}}
	public static function settings(){self::cap();$s=EBM_Settings::all();?><div class="wrap"><h1><?php esc_html_e('Electrical Booking Settings','electrical-booking-manager'); ?></h1><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><input type="hidden" name="action" value="ebm_save_settings"><?php wp_nonce_field('ebm_save_settings'); ?><table class="form-table"><tbody><tr><th>Business name</th><td><input name="business_name" class="regular-text" value="<?php echo esc_attr($s['business_name']); ?>"></td></tr><tr><th>Admin email</th><td><input name="admin_email" class="regular-text" value="<?php echo esc_attr($s['admin_email']); ?>"></td></tr><tr><th>Business days</th><td><?php foreach(array('0'=>'Sun','1'=>'Mon','2'=>'Tue','3'=>'Wed','4'=>'Thu','5'=>'Fri','6'=>'Sat') as $n=>$l): ?><label><input type="checkbox" name="business_days[]" value="<?php echo esc_attr($n); ?>" <?php checked(in_array($n,$s['business_days'],true)); ?>> <?php echo esc_html($l); ?></label> <?php endforeach; ?></td></tr><tr><th>Hours</th><td><input type="time" name="work_start" value="<?php echo esc_attr($s['work_start']); ?>"> to <input type="time" name="work_end" value="<?php echo esc_attr($s['work_end']); ?>"></td></tr><tr><th>Buffer minutes</th><td><input type="number" name="buffer_minutes" value="<?php echo esc_attr($s['buffer_minutes']); ?>"></td></tr><tr><th>Max bookings per slot</th><td><input type="number" min="1" name="max_bookings_per_slot" value="<?php echo esc_attr($s['max_bookings_per_slot']); ?>"></td></tr><tr><th>Holidays</th><td><textarea name="holidays" rows="5" class="large-text"><?php echo esc_textarea($s['holidays']); ?></textarea><p class="description">One YYYY-MM-DD date per line.</p></td></tr><tr><th>Global deposit</th><td><select name="global_deposit_type"><option value="percent" <?php selected($s['global_deposit_type'],'percent'); ?>>Percent</option><option value="fixed" <?php selected($s['global_deposit_type'],'fixed'); ?>>Fixed</option></select> <input type="number" step="0.01" name="global_deposit_value" value="<?php echo esc_attr($s['global_deposit_value']); ?>"></td></tr><tr><th>Stripe publishable key</th><td><input name="stripe_publishable_key" class="regular-text" value="<?php echo esc_attr($s['stripe_publishable_key']); ?>"></td></tr><tr><th>Stripe secret key</th><td><input name="stripe_secret_key" type="password" class="regular-text" placeholder="Leave blank to keep existing"></td></tr><tr><th>Stripe webhook secret</th><td><input name="stripe_webhook_secret" type="password" class="regular-text" placeholder="Leave blank to keep existing"></td></tr><tr><th>Google client ID</th><td><input name="google_client_id" class="regular-text" value="<?php echo esc_attr($s['google_client_id']); ?>"></td></tr><tr><th>Google client secret</th><td><input name="google_client_secret" type="password" class="regular-text" placeholder="Leave blank to keep existing"></td></tr><tr><th>Google calendar ID</th><td><input name="google_calendar_id" class="regular-text" value="<?php echo esc_attr($s['google_calendar_id']); ?>"></td></tr><tr><th>Google OAuth</th><td><?php if(EBM_Google::connected()): ?><strong>Connected</strong> <a class="button" href="<?php echo esc_url(wp_nonce_url(admin_url('admin-post.php?action=ebm_google_disconnect'),'ebm_google_disconnect')); ?>">Disconnect</a><?php else: ?><a class="button" href="<?php echo esc_url(wp_nonce_url(admin_url('admin-post.php?action=ebm_google_connect'),'ebm_google_connect')); ?>">Connect Google Calendar</a><?php endif; ?></td></tr></tbody></table><?php submit_button(); ?></form></div><?php }
	public static function save_settings(){self::cap();check_admin_referer('ebm_save_settings');EBM_Settings::save(wp_unslash($_POST));wp_safe_redirect(admin_url('admin.php?page=ebm-settings&updated=1'));exit;}
	public static function jobs(){self::cap();global $wpdb;$jobs=$wpdb->get_results('SELECT * FROM '.EBM_Helpers::table('jobs').' ORDER BY id DESC');?><div class="wrap"><h1>Jobs & Add-ons</h1><h2>Save job</h2><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><input type="hidden" name="action" value="ebm_save_job"><?php wp_nonce_field('ebm_save_job'); ?><table class="form-table"><tr><th>ID</th><td><input type="number" name="id" placeholder="blank for new"></td></tr><tr><th>Title</th><td><input name="title" class="regular-text" required></td></tr><tr><th>Description</th><td><textarea name="description" class="large-text"></textarea></td></tr><tr><th>Price</th><td><input type="number" step="0.01" name="price"></td></tr><tr><th>Duration minutes</th><td><input type="number" name="duration_minutes" value="60"></td></tr><tr><th>Active</th><td><input type="checkbox" name="is_active" value="1" checked></td></tr></table><?php submit_button('Save job'); ?></form><h2>Current jobs</h2><table class="widefat striped"><tr><th>ID</th><th>Title</th><th>Price</th><th>Duration</th><th>Active</th></tr><?php foreach($jobs as $j): ?><tr><td><?php echo esc_html($j->id); ?></td><td><?php echo esc_html($j->title); ?></td><td><?php echo esc_html(EBM_Helpers::money($j->price)); ?></td><td><?php echo esc_html($j->duration_minutes); ?></td><td><?php echo $j->is_active?'Yes':'No'; ?></td></tr><?php endforeach; ?></table><h2>Save add-on</h2><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><input type="hidden" name="action" value="ebm_save_addon"><?php wp_nonce_field('ebm_save_addon'); ?><table class="form-table"><tr><th>Job</th><td><select name="job_id"><?php foreach($jobs as $j): ?><option value="<?php echo esc_attr($j->id); ?>"><?php echo esc_html($j->title); ?></option><?php endforeach; ?></select></td></tr><tr><th>Title</th><td><input name="title" class="regular-text" required></td></tr><tr><th>Description</th><td><textarea name="description" class="large-text"></textarea></td></tr><tr><th>Price</th><td><input type="number" step="0.01" name="price"></td></tr><tr><th>Min qty</th><td><input type="number" name="min_qty" value="0"></td></tr><tr><th>Max qty</th><td><input type="number" name="max_qty" value="1"></td></tr><tr><th>Extra duration</th><td><input type="number" name="extra_duration_minutes" value="0"></td></tr></table><?php submit_button('Save add-on'); ?></form></div><?php }
	public static function save_job(){self::cap();check_admin_referer('ebm_save_job');global $wpdb;$now=current_time('mysql');$data=array('title'=>sanitize_text_field(wp_unslash($_POST['title']??'')),'description'=>sanitize_textarea_field(wp_unslash($_POST['description']??'')),'price'=>(float)($_POST['price']??0),'duration_minutes'=>absint($_POST['duration_minutes']??60),'is_active'=>isset($_POST['is_active'])?1:0,'updated_at'=>$now);$id=absint($_POST['id']??0);if($id){$wpdb->update(EBM_Helpers::table('jobs'),$data,array('id'=>$id),array('%s','%s','%f','%d','%d','%s'),array('%d'));}else{$data['created_at']=$now;$wpdb->insert(EBM_Helpers::table('jobs'),$data,array('%s','%s','%f','%d','%d','%s','%s'));}wp_safe_redirect(admin_url('admin.php?page=ebm-jobs&updated=1'));exit;}
	public static function save_addon(){self::cap();check_admin_referer('ebm_save_addon');global $wpdb;$now=current_time('mysql');$wpdb->insert(EBM_Helpers::table('addons'),array('job_id'=>absint($_POST['job_id']??0),'title'=>sanitize_text_field(wp_unslash($_POST['title']??'')),'description'=>sanitize_textarea_field(wp_unslash($_POST['description']??'')),'price'=>(float)($_POST['price']??0),'min_qty'=>absint($_POST['min_qty']??0),'max_qty'=>absint($_POST['max_qty']??1),'extra_duration_minutes'=>absint($_POST['extra_duration_minutes']??0),'is_active'=>1,'created_at'=>$now,'updated_at'=>$now),array('%d','%s','%s','%f','%d','%d','%d','%d','%s','%s'));wp_safe_redirect(admin_url('admin.php?page=ebm-jobs&updated=1'));exit;}
	public static function bookings(){self::cap();global $wpdb;$rows=$wpdb->get_results('SELECT b.*,j.title job_title,c.name,c.email,c.phone FROM '.EBM_Helpers::table('bookings').' b INNER JOIN '.EBM_Helpers::table('jobs').' j ON j.id=b.job_id INNER JOIN '.EBM_Helpers::table('customers').' c ON c.id=b.customer_id ORDER BY b.start_at DESC LIMIT 200');?><div class="wrap"><h1>Bookings</h1><table class="widefat striped"><tr><th>ID</th><th>Date</th><th>Customer</th><th>Job</th><th>Status</th><th>Total</th><th>Action</th></tr><?php foreach($rows as $b): ?><tr><td><?php echo esc_html($b->id); ?></td><td><?php echo esc_html(mysql2date('d M Y H:i',$b->start_at)); ?></td><td><?php echo esc_html($b->name); ?><br><small><?php echo esc_html($b->email); ?></small></td><td><?php echo esc_html($b->job_title); ?></td><td><?php echo esc_html($b->status); ?></td><td><?php echo esc_html(EBM_Helpers::money($b->total_amount)); ?></td><td><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><input type="hidden" name="action" value="ebm_update_booking"><input type="hidden" name="booking_id" value="<?php echo esc_attr($b->id); ?>"><?php wp_nonce_field('ebm_update_booking_'.$b->id); ?><select name="status"><option value="confirmed">Confirmed</option><option value="completed">Completed</option><option value="cancelled">Cancelled</option></select><button class="button">Update</button></form></td></tr><?php endforeach; ?></table></div><?php }
	public static function update_booking(){self::cap();$id=absint($_POST['booking_id']??0);check_admin_referer('ebm_update_booking_'.$id);$status=sanitize_key($_POST['status']??'');if(!in_array($status,array('confirmed','completed','cancelled'),true)){wp_die('Invalid status');}global $wpdb;$wpdb->update(EBM_Helpers::table('bookings'),array('status'=>$status,'updated_at'=>current_time('mysql')),array('id'=>$id),array('%s','%s'),array('%d'));if('completed'===$status){$b=$wpdb->get_row($wpdb->prepare('SELECT * FROM '.EBM_Helpers::table('bookings').' WHERE id=%d',$id));if($b&&(float)$b->balance_amount>0){$session=EBM_Stripe::checkout($id,(float)$b->balance_amount,'balance');if(!is_wp_error($session)&&!empty($session['url'])){EBM_Emails::balance($id,$session['url']);}}}wp_safe_redirect(admin_url('admin.php?page=ebm-bookings&updated=1'));exit;}
}
